fn pretty_print(node: &NodeRef, out: &mut Vec<u8>, depth: usize) {
    // Crude pretty-printer reproducing the reference's output shape.
    let indent = "  ".repeat(depth);

    if let Some(elem) = node.as_element() {
        out.push(b'\n');
        out.extend_from_slice(indent.as_bytes());
        out.push(b'<');
        out.extend_from_slice(elem.name.local.as_ref().as_bytes());
        let attrs = elem.attributes.borrow();
        for (name, attr) in attrs.map.iter() {
            out.push(b' ');
            out.extend_from_slice(name.local.as_ref().as_bytes());
            out.push(b'=');
            out.push(b'"');
            for c in attr.value.chars() {
                match c {
                    '&' => out.extend_from_slice(b"&amp;"),
                    '"' => out.extend_from_slice(b"&quot;"),
                    '\u{a0}' => out.extend_from_slice(b"&nbsp;"),
                    _ => {
                        let mut buf = [0; 4];
                        out.extend_from_slice(c.encode_utf8(&mut buf).as_bytes());
                    }
                }
            }
            out.push(b'"');
        }
        out.push(b'>');

        // children
        let has_only_text_first =
            matches!(node.first_child().and_then(|c| c.as_text().map(|_| ())), Some(()));

        if has_only_text_first {
            // Inline text directly after the open tag (no indent, no newline)
