                if let Some(t) = first.as_text() {
                    out.extend_from_slice(t.borrow().as_bytes());
                }
            }
            // Walk remaining children
            let mut sib = node.first_child().and_then(|c| c.next_sibling());
            while let Some(c) = sib {
                pretty_print(&c, out, depth + 1);
                sib = c.next_sibling();
            }
        } else {
            for c in node.children() {
                pretty_print(&c, out, depth + 1);
            }
        }

        // Don't emit close tag for void elements
        if is_void(elem.name.local.as_ref()) {
            return;
        }

        out.push(b'\n');
        out.extend_from_slice(indent.as_bytes());
        out.push(b'<');
        out.push(b'/');
        out.extend_from_slice(elem.name.local.as_ref().as_bytes());
        out.push(b'>');
    } else if let Some(t) = node.as_text() {
        out.push(b'\n');
        out.extend_from_slice(indent.as_bytes());
        out.extend_from_slice(t.borrow().as_bytes());
    } else {
        // doctype/comment/etc: skip for now
    }
}

